const DatabaseTableOutputOptions = @import("database_table_output_options.zig").DatabaseTableOutputOptions;
const DatabaseOutputMode = @import("database_output_mode.zig").DatabaseOutputMode;

/// Represents a JDBC database output object which defines the output
/// destination for
/// a DataBrew recipe job to write into.
pub const DatabaseOutput = struct {
    /// Represents options that specify how and where DataBrew writes the database
    /// output
    /// generated by recipe jobs.
    database_options: DatabaseTableOutputOptions,

    /// The output mode to write into the database. Currently supported option:
    /// NEW_TABLE.
    database_output_mode: ?DatabaseOutputMode,

    /// The Glue connection that stores the connection information for the
    /// target database.
    glue_connection_name: []const u8,

    pub const json_field_names = .{
        .database_options = "DatabaseOptions",
        .database_output_mode = "DatabaseOutputMode",
        .glue_connection_name = "GlueConnectionName",
    };
};
